import { useState } from "react";
import Sidebar from "./Sidebar";

export default function MaterialExpenseManagement() {

  const today = new Date().toISOString().split("T")[0];

  const [activeForm, setActiveForm] = useState("");

  const [materials, setMaterials] = useState([]);
  const [expenses, setExpenses] = useState([]);

  const onlyText = /^[A-Za-z\s]+$/;

  // ================= MATERIAL FORM =================
  const [materialForm, setMaterialForm] = useState({
    name: "",
    quantity: "",
    unit: "Kg",
    supplier: "",
    purchaseDate: today,
    costPerUnit: "",
    project: "",
    bill: "",
    remarks: ""
  });

  // ================= EXPENSE FORM =================
  const [expenseForm, setExpenseForm] = useState({
    title: "",
    type: "Labor",
    amount: "",
    paymentMethod: "Cash",
    date: today,
    project: "",
    paidTo: "",
    bill: "",
    notes: ""
  });

  // ================= CALCULATIONS =================
  const totalMaterialCost = materials.reduce(
    (sum, m) => sum + Number(m.totalCost || 0),
    0
  );

  const totalExpenseCost = expenses.reduce(
    (sum, e) => sum + Number(e.amount || 0),
    0
  );

  // ================= MATERIAL HANDLERS =================
  const handleMaterialChange = (e) => {
    const { name, value } = e.target;

    // Only text validation for specific fields
    if ((name === "name" || name === "supplier") && value && !onlyText.test(value)) {
      return;
    }

    setMaterialForm({ ...materialForm, [name]: value });
  };

  const addMaterial = (e) => {
    e.preventDefault();

    if (!onlyText.test(materialForm.name)) {
      return alert("Material Name → Only characters allowed");
    }

    if (!onlyText.test(materialForm.supplier)) {
      return alert("Supplier Name → Only characters allowed");
    }

    if (materialForm.purchaseDate < today) {
      return alert("Date must be today or future");
    }

    const total =
      Number(materialForm.quantity) * Number(materialForm.costPerUnit);

    const newMaterial = {
      ...materialForm,
      totalCost: total
    };

    setMaterials([...materials, newMaterial]);
    setActiveForm("");
  };

  // ================= EXPENSE HANDLERS =================
  const handleExpenseChange = (e) => {
    const { name, value } = e.target;

    if ((name === "title" || name === "paidTo") && value && !onlyText.test(value)) {
      return;
    }

    if (name === "amount" && Number(value) > 100000000) {
      return;
    }

    setExpenseForm({ ...expenseForm, [name]: value });
  };

  const addExpense = (e) => {
    e.preventDefault();

    if (!onlyText.test(expenseForm.title)) {
      return alert("Expense Title → Only characters allowed");
    }

    if (!onlyText.test(expenseForm.paidTo)) {
      return alert("Paid To → Only characters allowed");
    }

    if (Number(expenseForm.amount) > 100000000) {
      return alert("Amount cannot exceed ₹10 Crore");
    }

    if (expenseForm.date < today) {
      return alert("Date must be today or future");
    }

    setExpenses([...expenses, expenseForm]);
    setActiveForm("");
  };

  return (
    <div className="flex bg-gray-100 min-h-screen">

      <Sidebar />

      <div className="flex-1 p-8">

        {/* ================= DASHBOARD ================= */}
        {activeForm === "" && (
          <>
            <h1 className="text-3xl font-bold mb-6">
              Material & Expense Dashboard
            </h1>

            <div className="grid grid-cols-3 gap-6 mb-8">

              <div className="bg-white p-6 rounded shadow">
                <p>Total Material Cost</p>
                <h2 className="text-xl font-bold">₹{totalMaterialCost}</h2>
              </div>

              <div className="bg-white p-6 rounded shadow">
                <p>Total Expenses</p>
                <h2 className="text-xl font-bold">₹{totalExpenseCost}</h2>
              </div>

              <div className="bg-white p-6 rounded shadow">
                <p>Total Records</p>
                <h2 className="text-xl font-bold">
                  {materials.length + expenses.length}
                </h2>
              </div>

            </div>

            <div className="flex gap-4">
              <button onClick={() => setActiveForm("material")} className="bg-orange-500 text-white px-5 py-2 rounded">
                + Material Form
              </button>

              <button onClick={() => setActiveForm("expense")} className="bg-blue-500 text-white px-5 py-2 rounded">
                + Expense Form
              </button>
            </div>
          </>
        )}

        {/* ================= MATERIAL FORM ================= */}
        {activeForm === "material" && (
          <div className="bg-white p-6 mt-6 rounded shadow">

            <h2 className="text-xl font-bold mb-4">Material Form</h2>

            <form onSubmit={addMaterial} className="grid grid-cols-3 gap-4">

              <div>
                <label>Material Name</label>
                <input name="name" value={materialForm.name} onChange={handleMaterialChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Quantity</label>
                <input name="quantity" type="number" onChange={handleMaterialChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Unit</label>
                <select name="unit" onChange={handleMaterialChange} className="border p-2 w-full">
                  <option>Kg</option>
                  <option>Ton</option>
                  <option>Bags</option>
                  <option>Liters</option>
                  <option>Pcs</option>
                  <option>Cubic Meter</option>
                </select>
              </div>

              <div>
                <label>Supplier Name</label>
                <input name="supplier" value={materialForm.supplier} onChange={handleMaterialChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Purchase Date</label>
                <input type="date" min={today} name="purchaseDate" value={materialForm.purchaseDate} onChange={handleMaterialChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Cost per Unit</label>
                <input name="costPerUnit" type="number" onChange={handleMaterialChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Project Name</label>
                <input name="project" onChange={handleMaterialChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Bill Upload</label>
                <input type="file" name="bill" onChange={handleMaterialChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Remarks</label>
                <input name="remarks" onChange={handleMaterialChange} className="border p-2 w-full" />
              </div>

              <button className="bg-green-500 text-white px-4 py-2 rounded col-span-3">
                Save Material
              </button>

            </form>

            <button onClick={() => setActiveForm("")} className="mt-4 underline">Back</button>

          </div>
        )}

        {/* ================= EXPENSE FORM ================= */}
        {activeForm === "expense" && (
          <div className="bg-white p-6 mt-6 rounded shadow">

            <h2 className="text-xl font-bold mb-4">Expense Form</h2>

            <form onSubmit={addExpense} className="grid grid-cols-3 gap-4">

              <div>
                <label>Expense Title</label>
                <input name="title" value={expenseForm.title} onChange={handleExpenseChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Expense Type</label>
                <select name="type" onChange={handleExpenseChange} className="border p-2 w-full">
                  <option>Labor</option>
                  <option>Transport</option>
                  <option>Equipment</option>
                  <option>Maintenance</option>
                  <option>Office</option>
                  <option>Misc</option>
                </select>
              </div>

              <div>
                <label>Amount</label>
                <input name="amount" type="number" onChange={handleExpenseChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Payment Method</label>
                <select name="paymentMethod" onChange={handleExpenseChange} className="border p-2 w-full">
                  <option>Cash</option>
                  <option>UPI</option>
                  <option>Bank</option>
                </select>
              </div>

              <div>
                <label>Expense Date</label>
                <input type="date" min={today} name="date" value={expenseForm.date} onChange={handleExpenseChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Project Name</label>
                <input name="project" onChange={handleExpenseChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Paid To</label>
                <input name="paidTo" value={expenseForm.paidTo} onChange={handleExpenseChange} className="border p-2 w-full" />
              </div>

              <div>
                <label>Bill Upload</label>
                <input type="file" name="bill" onChange={handleExpenseChange} className="border p-2 w-full" />
              </div>

              <div className="col-span-3">
                <label>Notes</label>
                <textarea name="notes" onChange={handleExpenseChange} className="border p-2 w-full" />
              </div>

              <button className="bg-blue-500 text-white px-4 py-2 rounded col-span-3">
                Save Expense
              </button>

            </form>

            <button onClick={() => setActiveForm("")} className="mt-4 underline">Back</button>

          </div>
        )}

      </div>
    </div>
  );
}
